// ═══════════════════════════════════════════
// CHECK FOR UPCOMING BIRTHDAYS
// Finds birthdays happening today or within 7 days
//
// To change the reminder window, edit the
// reminderDays variable below (default: 7)
// ═══════════════════════════════════════════

const reminderDays = 7;
const people = $input.all();

const today = new Date();
today.setHours(0, 0, 0, 0);

const alerts = [];

for (const item of people) {
  const p = item.json;
  if (!p.name || !p.birthday) continue;

  let bday;
  try {
    bday = new Date(p.birthday);
    if (isNaN(bday.getTime())) continue;
  } catch { continue; }

  const thisYear = new Date(today.getFullYear(), bday.getMonth(), bday.getDate());
  const nextBday = thisYear < today
    ? new Date(today.getFullYear() + 1, bday.getMonth(), bday.getDate())
    : thisYear;

  const daysUntil = Math.round((nextBday - today) / (1000 * 60 * 60 * 24));

  if (daysUntil === 0) {
    alerts.push({
      name: p.name,
      type: 'today',
      days_until: 0,
      age: today.getFullYear() - bday.getFullYear(),
      relationship: p.relationship || 'Contact',
      interests: p.interests || '',
      date: nextBday.toISOString().split('T')[0],
    });
  } else if (daysUntil === reminderDays) {
    alerts.push({
      name: p.name,
      type: 'upcoming',
      days_until: daysUntil,
      age: nextBday.getFullYear() - bday.getFullYear(),
      relationship: p.relationship || 'Contact',
      interests: p.interests || '',
      date: nextBday.toISOString().split('T')[0],
    });
  }
}

if (alerts.length === 0) {
  return [{ json: { _skip: true } }];
}

return alerts.map(a => ({ json: a }));

// ═══════════════════════════════════════════
// FORMAT HEADER + BUILD AI PROMPT
// Creates the notification header and prepares
// a personalized prompt for the AI model
// ═══════════════════════════════════════════

const items = $input.all();
const results = [];

for (const item of items) {
  const a = item.json;

  if (a._skip) continue;
  if (!a.name) continue;

  let header = '';

  if (a.type === 'today') {
    header += `🎂 TODAY — ${a.name} turns ${a.age}!\n`;
    header += `👤 ${a.relationship}\n`;
    header += `📅 ${a.date}\n`;
  } else {
    header += `📅 REMINDER — ${a.name}'s birthday in ${a.days_until} days\n`;
    header += `🎂 Turning ${a.age} on ${a.date}\n`;
    header += `👤 ${a.relationship}\n`;
  }

  if (a.interests) {
    header += `💡 Interests: ${a.interests}\n`;
  }

  const chatInput = `You are a thoughtful friend. Write a short, warm birthday message (3-4 lines max) for:\n\nName: ${a.name}\nAge: ${a.age}\nRelationship: ${a.relationship}\nInterests: ${a.interests || 'not specified'}\nEvent: ${a.type === 'today' ? 'Birthday is TODAY' : 'Birthday is coming up soon'}\n\nAlso suggest 3 personalized gift ideas based on their interests (one line each, with price estimate $20-100).\n\nFormat your response EXACTLY like this:\n\n💌 MESSAGE:\n[your warm message here]\n\n🎁 GIFT IDEAS:\n1. [specific gift] ($XX)\n2. [specific gift] ($XX)\n3. [specific gift] ($XX)`;

  results.push({ json: {
    header: header,
    chatInput: chatInput,
    name: a.name,
  } });
}

if (results.length === 0) {
  return [];
}

return results;

// ═══════════════════════════════════════════
// COMBINE HEADER + AI RESPONSE
// Merges the formatted header with AI output
// into one final Telegram message
// ═══════════════════════════════════════════

const items = $input.all();
const results = [];

for (const item of items) {
  const header = $('🎁 Format Messages').item.json.header || '';
  const aiResponse = item.json.text || item.json.response || item.json.output || '';

  const finalMessage = header + '\n' + aiResponse;

  results.push({ json: { message: finalMessage } });
}

return results;
